class Solution:
    def numSpecialEquivGroups(self, words):
        groups = set()
        for w in words:
            even = tuple(sorted(w[i] for i in range(0, len(w), 2)))
            odd = tuple(sorted(w[i] for i in range(1, len(w), 2)))
            groups.add((even, odd))
        return len(groups)

