class Solution:
    def numSpecialEquivGroups(self, words):
        seen = set()
        for w in words:
            even_sorted = ''.join(sorted(w[i] for i in range(0, len(w), 2)))
            odd_sorted = ''.join(sorted(w[i] for i in range(1, len(w), 2)))
            seen.add((even_sorted, odd_sorted))
        return len(seen)

