var numSpecialEquivGroups = function(words) {
    const sigs = new Set();
    for (const w of words) {
        const even = w.split('').filter((_, i) => i % 2 === 0).sort().join('');
        const odd  = w.split('').filter((_, i) => i % 2 === 1).sort().join('');
        sigs.add(even + '|' + odd);
    }
    return sigs.size;
};
